// C# — Array: Create, Search, Indexing, Update
int[] arr = new int[5] { 10, 20, 30, 40, 50 };

// Access by index
int value = arr[2]; // 30

// Search (linear)
int target = 40;
int foundIndex = -1;
for (int i = 0; i < arr.Length; i++)
{
    if (arr[i] == target)
    {
        foundIndex = i;
        break;
    }
}

// Update
arr[1] = 99; // arr is now { 10, 99, 30, 40, 50 }

// C++ — Array: Create, Search, Indexing, Update
#include <iostream>
using namespace std;

int main() {
    int arr[5] = {10, 20, 30, 40, 50};

    // Access by index
    int value = arr[2]; // 30

    // Search (linear)
    int target = 40;
    int foundIndex = -1;
    for (int i = 0; i < 5; i++) {
        if (arr[i] == target) {
            foundIndex = i;
            break;
        }
    }

    // Update
    arr[1] = 99; // arr is now {10, 99, 30, 40, 50}

    return 0;
}

